// src/pages/dashboard/ContentDashboard.js
import React from "react";
import Layout from "../../components/layout/Layout";
import Navbar from "../../components/Navbar";
import Sidebar from "../../components/Sidebar";
import { Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend);

function ContentDashboard() {
  // Chart Data
  const chartData = {
    labels: ["Week 1", "Week 2", "Week 3", "Week 4"],
    datasets: [
      {
        label: "New Content Uploaded",
        data: [5, 8, 3, 6],
        backgroundColor: "#059669",
      },
      {
        label: "Content Updates",
        data: [2, 4, 3, 5],
        backgroundColor: "#10b981",
      },
    ],
  };

  const chartOptions = {
    responsive: true,
    plugins: {
      legend: { position: "top" },
      title: { display: true, text: "Content Upload Activity" },
    },
  };

  return (
    <Layout pageTitle="Content Creator Dashboard - NexaLearn LMS">
      <Navbar />
      <div className="d-flex" style={{ minHeight: "80vh" }}>
        <Sidebar />
        <div className="flex-grow-1 p-4">
          {/* Header */}
          <div className="d-flex justify-content-between align-items-center mb-4">
            <h2 style={{ fontWeight: "700", color: "#059669" }}>Content Creator Overview</h2>
            <button className="btn btn-success">+ Add New Content</button>
          </div>

          {/* Quick Info Cards */}
          <div className="row g-4 mb-4">
            <div className="col-md-4">
              <div className="card shadow-sm p-4" style={{ borderRadius: "12px", borderLeft: "5px solid #059669" }}>
                <h6>Total Content</h6>
                <h2 className="fw-bold">24</h2>
                <small className="text-success">+3 this week</small>
              </div>
            </div>

            <div className="col-md-4">
              <div className="card shadow-sm p-4" style={{ borderRadius: "12px", borderLeft: "5px solid #10b981" }}>
                <h6>Drafts</h6>
                <h2 className="fw-bold">5</h2>
                <small className="text-warning">Pending review</small>
              </div>
            </div>

            <div className="col-md-4">
              <div className="card shadow-sm p-4" style={{ borderRadius: "12px", borderLeft: "5px solid #14b8a6" }}>
                <h6>Published</h6>
                <h2 className="fw-bold">19</h2>
                <small className="text-success">+2 this week</small>
              </div>
            </div>
          </div>

          {/* Chart Section */}
          <div className="card shadow-sm border-0 p-4 mb-4" style={{ borderRadius: "12px" }}>
            <h5 className="mb-3 fw-semibold">Content Activity Overview</h5>
            <Bar data={chartData} options={chartOptions} />
          </div>

          {/* Action Panel */}
          <div className="card shadow-sm p-4" style={{ borderRadius: "12px", backgroundColor: "#f0fdf4" }}>
            <h5 className="mb-3 fw-semibold">Manage Content</h5>
            <p style={{ color: "#065f46", lineHeight: "1.6" }}>
              Upload new course materials, update existing content, and track content performance. 
              Ensure educational quality and keep your students engaged.
            </p>
            <button
              className="btn btn-success"
              style={{ fontWeight: "600" }}
            >
              Create New Content
            </button>
          </div>
        </div>
      </div>
    </Layout>
  );
}

export default ContentDashboard;
